_PARAMS = None

def _decode_param(name):
    spec = PARAM_SPECS[name]
    compressed = base64.b85decode(PARAM_BYTES[name].encode("ascii"))
    quantized = np.frombuffer(zlib.decompress(compressed), dtype=np.int8).reshape(spec["shape"])
    return (quantized.astype(np.float32) * spec["scale"]).astype(np.float32)


def _get_params():
    global _PARAMS
    if _PARAMS is None:
        _PARAMS = {name: _decode_param(name) for name in PARAM_SPECS}
    return _PARAMS


def extract_likert_value(value):
    if pd.isna(value):
        return np.nan
    match = re.match(r"^(\d+)", str(value).strip())
    return float(match.group(1)) if match else np.nan


def parse_price_value(value):
    if pd.isna(value):
        return np.nan

    text = str(value).lower().strip().replace(",", "")
    if not text:
        return np.nan

    range_match = re.search(r"(\d+\.?\d*)\s*(?:-|–|to)\s*(\d+\.?\d*)", text)
    if range_match:
        low, high = float(range_match.group(1)), float(range_match.group(2))
        return (low + high) / 2

    for pattern, multiplier in (
        (r"(\d+\.?\d*)\s*(?:billion|bn|b)\b", 1_000_000_000),
        (r"(\d+\.?\d*)\s*(?:million|m)\b", 1_000_000),
        (r"(\d+\.?\d*)\s*k\b", 1_000),
    ):
        mult_match = re.search(pattern, text)
        if mult_match:
            return float(mult_match.group(1)) * multiplier

    first_num = re.search(r"(\d+\.?\d*)", text)
    if first_num:
        return float(first_num.group(1))

    return np.nan


def extract_words(value):
    if pd.isna(value):
        return set()
    return set(WORD_PATTERN.findall(str(value).lower()))


def _prepare_dataframe(data):
    df = pd.DataFrame(data).copy()
    df = df.rename(columns=RENAME_MAP)

    required_columns = ["price", *NUMERIC_COLS, *WORD_COLS]
    for col in required_columns:
        if col not in df.columns:
            df[col] = np.nan

    for col in ["emotion_rating", "colors", "objects"]:
        df[col] = pd.to_numeric(df[col], errors="coerce")

    for col in LIKERT_COLS:
        df[col] = df[col].apply(extract_likert_value)

    df["price_clean"] = df["price"].apply(parse_price_value)
    return df


def _build_feature_matrix(data):
    df = _prepare_dataframe(data)

    numeric_frame = df[NUMERIC_COLS].copy()
    numeric_frame = numeric_frame.fillna(TRAIN_MEDIANS)
    numeric_frame["price_clean"] = numeric_frame["price_clean"].clip(lower=0, upper=float(PRICE_CAP))
    numeric_frame["price_clean"] = np.log1p(numeric_frame["price_clean"])

    X_num = ((numeric_frame - TRAIN_MEANS) / TRAIN_STDS).to_numpy(dtype=np.float32)
    parts = [X_num]

    for col in WORD_COLS:
        vocabulary = VOCABULARIES[col]
        matrix = np.zeros((len(df), len(vocabulary)), dtype=np.float32)
        for row_idx, value in enumerate(df[col].fillna("")):
            for word in extract_words(value):
                col_idx = vocabulary.get(word)
                if col_idx is not None:
                    matrix[row_idx, col_idx] = 1.0
        parts.append(matrix)

    return np.concatenate(parts, axis=1).astype(np.float32)


def _relu(x):
    return np.maximum(0, x)


def _softmax(z):
    shifted = z - z.max(axis=1, keepdims=True)
    exp_z = np.exp(shifted)
    return exp_z / exp_z.sum(axis=1, keepdims=True)


def _predict_indices_from_features(X):
    params = _get_params()
    Z1 = X @ params["W0"] + params["b0"]
    A1 = _relu(Z1)
    Z2 = A1 @ params["W1"] + params["b1"]
    A2 = _relu(Z2)
    Z3 = A2 @ params["W2"] + params["b2"]
    probabilities = _softmax(Z3)
    return probabilities.argmax(axis=1)


def cleanData(row):
    """
    Standardize one row into the same feature vector used in nnready.ipynb.
    """
    if isinstance(row, pd.Series):
        row_df = row.to_frame().T
    else:
        row_df = pd.DataFrame([row])
    return _build_feature_matrix(row_df)


def predict(row):
    """
    Predict a label for one cleaned row or one raw pandas Series.
    """
    if isinstance(row, pd.Series):
        features = cleanData(row)
    else:
        features = np.asarray(row, dtype=np.float32)
        if features.ndim == 1:
            features = features.reshape(1, -1)
    pred_idx = int(_predict_indices_from_features(features)[0])
    return CLASS_NAMES[pred_idx]


def predict_all(fileName):
    """
    Read a CSV file and return a list of painting predictions.
    """
    df = pd.read_csv(fileName)
    X = _build_feature_matrix(df)
    pred_indices = _predict_indices_from_features(X)
    return [CLASS_NAMES[int(idx)] for idx in pred_indices]


if __name__ == "__main__":
    if len(sys.argv) != 2:
        raise SystemExit("Usage: python pred.py <csv_file>")

    for prediction in predict_all(sys.argv[1]):
        print(prediction)
